components.DocumentReviewFlow:
export default function DocumentReviewFlow() {
  const [clients, setClients] = useState([]);
  const [clientId, setClientId] = useState("");
  const [client, setClient] = useState(null);
  const [docs, setDocs] = useState([]);
  const [loading, setLoading] = useState(false);
  const [docsLoading, setDocsLoading] = useState(false);
  const [actionState, setActionState] = useState({}); // docId -> {phase, reason, showReason}

  useEffect(() => {
    tools.host_listClients({}).then((r) => setClients(r.data || []));
  }, []);

  useEffect(() => {
    if (!clientId) { setClient(null); setDocs([]); return; }
    setDocsLoading(true);
    Promise.all([
      tools.host_getClient({ id: clientId }),
      tools.host_listClientDocuments({ id: clientId }),
    ]).then(([c, d]) => {
      setClient(c);
      const reviewable = (d.data || []).filter(doc => doc.status === "received" || doc.status === "needs_review");
      setDocs(reviewable);
      setDocsLoading(false);
    });
  }, [clientId]);

  const initAction = (docId, type) => {
    setActionState(prev => ({
      ...prev,
      [docId]: { phase: "idle", reason: "", showReason: type === "reject", pendingAction: type }
    }));
  };

  const setReason = (docId, val) => {
    setActionState(prev => ({ ...prev, [docId]: { ...prev[docId], reason: val } }));
  };

  const submit = async (doc, action) => {
    const state = actionState[doc.id] || {};
    setActionState(prev => ({ ...prev, [doc.id]: { ...prev[doc.id], phase: "sending" } }));
    const result = await tools.host_setDocumentStatus({
      id: clientId,
      docId: doc.id,
      body: {
        action,
        fileName: doc.fileName || doc.file_name || "",
        reason: state.reason || "",
      }
    });
    const nextPhase = result && result.status === "pending-approval" ? "awaiting" : action === "verify" ? "verified" : "rejected";
    setActionState(prev => ({ ...prev, [doc.id]: { ...prev[doc.id], phase: nextPhase } }));
  };

  const cancel = (docId) => {
    setActionState(prev => { const n = { ...prev }; delete n[docId]; return n; });
  };

  const statusColor = (s) => ({
    received: "var(--vendo-color-accent)",
    needs_review: "#b07a00",
    verified: "#2a7a4b",
    rejected: "var(--vendo-color-danger)",
  }[s] || "var(--vendo-color-muted)");

  const statusLabel = (s) => ({
    received: "Received",
    needs_review: "Needs review",
    verified: "Verified",
    rejected: "Rejected",
  }[s] || s);

  const reviewableDocs = docs;

  return (
    <div style={{ fontFamily: "var(--vendo-font-family)", color: "var(--vendo-color-text)", display: "grid", gap: 20 }}>
      {/* Client picker */}
      <div style={{ background: "var(--vendo-color-surface)", border: "1px solid var(--vendo-color-border)", borderRadius: "var(--vendo-radius-medium)", padding: 20 }}>
        <div style={{ fontSize: 13, fontWeight: 600, color: "var(--vendo-color-muted)", marginBottom: 8, textTransform: "uppercase", letterSpacing: "0.05em" }}>Select client</div>
        <select
          value={clientId}
          onChange={e => { setClientId(e.target.value); setActionState({}); }}
          style={{ width: "100%", padding: "10px 12px", borderRadius: "var(--vendo-radius-small)", border: "1px solid var(--vendo-color-border)", fontFamily: "var(--vendo-font-family)", fontSize: 15, background: "var(--vendo-color-background)", color: "var(--vendo-color-text)", appearance: "auto" }}
        >
          <option value="">Choose a client…</option>
          {clients.map(c => (
            <option key={c.id} value={c.id}>{c.name}{c.entityType ? ` — ${c.entityType}` : ""}</option>
          ))}
        </select>
      </div>

      {/* Client summary */}
      {client && (
        <div style={{ background: "var(--vendo-color-surface)", border: "1px solid var(--vendo-color-border)", borderRadius: "var(--vendo-radius-medium)", padding: 20, display: "flex", gap: 32, alignItems: "center", flexWrap: "wrap" }}>
          <div>
            <div style={{ fontSize: 20, fontWeight: 700 }}>{client.name}</div>
            <div style={{ fontSize: 13, color: "var(--vendo-color-muted)", marginTop: 2 }}>{client.entityType || ""}{client.assignedStaff ? ` · ${client.assignedStaff}` : ""}</div>
          </div>
          <div style={{ display: "flex", gap: 24, flexWrap: "wrap" }}>
            <div style={{ textAlign: "center" }}>
              <div style={{ fontSize: 22, fontWeight: 700 }}>{reviewableDocs.length}</div>
              <div style={{ fontSize: 12, color: "var(--vendo-color-muted)" }}>Awaiting review</div>
            </div>
            {client.filingDeadline && (
              <div style={{ textAlign: "center" }}>
                <div style={{ fontSize: 15, fontWeight: 600 }}>{new Date(client.filingDeadline).toLocaleDateString("en-US", { month: "short", day: "numeric", year: "numeric" })}</div>
                <div style={{ fontSize: 12, color: "var(--vendo-color-muted)" }}>Filing deadline</div>
              </div>
            )}
          </div>
        </div>
      )}

      {/* Document list */}
      {clientId && docsLoading && (
        <div style={{ padding: 32, textAlign: "center", color: "var(--vendo-color-muted)", fontSize: 14 }}>Loading documents…</div>
      )}

      {clientId && !docsLoading && reviewableDocs.length === 0 && (
        <div style={{ background: "var(--vendo-color-surface)", border: "1px solid var(--vendo-color-border)", borderRadius: "var(--vendo-radius-medium)", padding: 32, textAlign: "center", color: "var(--vendo-color-muted)", fontSize: 14 }}>
          No documents awaiting review for this client.
        </div>
      )}

      {!docsLoading && reviewableDocs.map(doc => {
        const state = actionState[doc.id] || {};
        const phase = state.phase;
        const isDone = phase === "verified" || phase === "rejected" || phase === "awaiting";

        return (
          <div key={doc.id} style={{ background: "var(--vendo-color-surface)", border: `1px solid ${isDone ? "var(--vendo-color-border)" : "var(--vendo-color-border)"}`, borderRadius: "var(--vendo-radius-medium)", padding: 20, opacity: isDone ? 0.75 : 1, transition: "opacity 0.2s" }}>
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", flexWrap: "wrap", gap: 8 }}>
              <div>
                <div style={{ fontWeight: 600, fontSize: 15 }}>{doc.name || doc.documentType || "Document"}</div>
                {doc.fileName && (
                  <div style={{ fontSize: 13, color: "var(--vendo-color-muted)", marginTop: 2 }}>📎 {doc.fileName}</div>
                )}
                {doc.uploadedAt && (
                  <div style={{ fontSize: 12, color: "var(--vendo-color-muted)", marginTop: 2 }}>Uploaded {new Date(doc.uploadedAt).toLocaleDateString("en-US", { month: "short", day: "numeric", year: "numeric" })}</div>
                )}
              </div>
              <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                <span style={{ fontSize: 12, fontWeight: 600, padding: "3px 10px", borderRadius: 99, background: statusColor(doc.status) + "18", color: statusColor(doc.status), border: `1px solid ${statusColor(doc.status)}40` }}>
                  {statusLabel(doc.status)}
                </span>
              </div>
            </div>

            {/* Done states */}
            {phase === "awaiting" && (
              <div style={{ marginTop: 14, padding: "10px 14px", borderRadius: "var(--vendo-radius-small)", background: "#f5f5f0", color: "var(--vendo-color-muted)", fontSize: 13 }}>
                Awaiting your approval…
              </div>
            )}
            {phase === "verified" && (
              <div style={{ marginTop: 14, padding: "10px 14px", borderRadius: "var(--vendo-radius-small)", background: "#edf7f1", color: "#2a7a4b", fontSize: 13, fontWeight: 600 }}>
                ✓ Marked as verified
              </div>
            )}
            {phase === "rejected" && (
              <div style={{ marginTop: 14, padding: "10px 14px", borderRadius: "var(--vendo-radius-small)", background: "#fdf0ef", color: "var(--vendo-color-danger)", fontSize: 13, fontWeight: 600 }}>
                ✗ Returned to client with note
              </div>
            )}

            {/* Action buttons — idle, no pending action chosen */}
            {!isDone && !state.pendingAction && (
              <div style={{ display: "flex", gap: 10, marginTop: 16 }}>
                <button
                  onClick={() => initAction(doc.id, "verify")}
                  style={{ padding: "8px 18px", borderRadius: "var(--vendo-radius-small)", border: "none", background: "var(--vendo-color-accent)", color: "var(--vendo-color-accentText, #fff)", fontFamily: "var(--vendo-font-family)", fontSize: 14, fontWeight: 600, cursor: "pointer" }}
                >
                  Verify
                </button>
                <button
                  onClick={() => initAction(doc.id, "reject")}
                  style={{ padding: "8px 18px", borderRadius: "var(--vendo-radius-small)", border: "1px solid var(--vendo-color-danger)", background: "transparent", color: "var(--vendo-color-danger)", fontFamily: "var(--vendo-font-family)", fontSize: 14, fontWeight: 600, cursor: "pointer" }}
                >
                  Reject
                </button>
              </div>
            )}

            {/* Verify confirmation */}
            {!isDone && state.pendingAction === "verify" && (
              <div style={{ marginTop: 16, padding: 14, background: "#f5f5f0", borderRadius: "var(--vendo-radius-small)", display: "grid", gap: 10 }}>
                <div style={{ fontSize: 13, color: "var(--vendo-color-muted)" }}>Confirm this document is correct and complete.</div>
                <div style={{ display: "flex", gap: 8 }}>
                  <button
                    onClick={() => submit(doc, "verify")}
                    disabled={state.phase === "sending"}
                    style={{ padding: "8px 18px", borderRadius: "var(--vendo-radius-small)", border: "none", background: "var(--vendo-color-accent)", color: "#fff", fontFamily: "var(--vendo-font-family)", fontSize: 14, fontWeight: 600, cursor: state.phase === "sending" ? "not-allowed" : "pointer", opacity: state.phase === "sending" ? 0.6 : 1 }}
                  >
                    {state.phase === "sending" ? "Verifying…" : "Confirm verify"}
                  </button>
                  <button onClick={() => cancel(doc.id)} style={{ padding: "8px 14px", borderRadius: "var(--vendo-radius-small)", border: "1px solid var(--vendo-color-border)", background: "transparent", color: "var(--vendo-color-muted)", fontFamily: "var(--vendo-font-family)", fontSize: 14, cursor: "pointer" }}>Cancel</button>
                </div>
              </div>
            )}

            {/* Reject flow with reason */}
            {!isDone && state.pendingAction === "reject" && (
              <div style={{ marginTop: 16, padding: 14, background: "#fdf0ef", borderRadius: "var(--vendo-radius-small)", display: "grid", gap: 10 }}>
                <label style={{ fontSize: 13, fontWeight: 600, color: "var(--vendo-color-danger)" }}>Note to client (required)</label>
                <textarea
                  value={state.reason || ""}
                  onChange={e => setReason(doc.id, e.target.value)}
                  placeholder="Explain what's wrong or what the client should re-upload…"
                  rows={3}
                  style={{ width: "100%", padding: "8px 10px", borderRadius: "var(--vendo-radius-small)", border: "1px solid var(--vendo-color-danger)", fontFamily: "var(--vendo-font-family)", fontSize: 14, resize: "vertical", boxSizing: "border-box", background: "var(--vendo-color-surface)" }}
                />
                <div style={{ display: "flex", gap: 8 }}>
                  <button
                    onClick={() => submit(doc, "reject")}
                    disabled={!state.reason || !state.reason.trim() || state.phase === "sending"}
                    style={{ padding: "8px 18px", borderRadius: "var(--vendo-radius-small)", border: "none", background: "var(--vendo-color-danger)", color: "#fff", fontFamily: "var(--vendo-font-family)", fontSize: 14, fontWeight: 600, cursor: (!state.reason || !state.reason.trim() || state.phase === "sending") ? "not-allowed" : "pointer", opacity: (!state.reason || !state.reason.trim() || state.phase === "sending") ? 0.6 : 1 }}
                  >
                    {state.phase === "sending" ? "Rejecting…" : "Reject & notify client"}
                  </button>
                  <button onClick={() => cancel(doc.id)} style={{ padding: "8px 14px", borderRadius: "var(--vendo-radius-small)", border: "1px solid var(--vendo-color-border)", background: "transparent", color: "var(--vendo-color-muted)", fontFamily: "var(--vendo-font-family)", fontSize: 14, cursor: "pointer" }}>Cancel</button>
                </div>
              </div>
            )}
          </div>
        );
      })}
    </div>
  );
}
